291	export function markThreadVisited(
292	  state: AppState,
293	  threadId: ThreadId,
294	  visitedAt?: string,
295	): AppState {
296	  const at = visitedAt ?? new Date().toISOString();
297	  const visitedAtMs = Date.parse(at);
298	  const threads = updateThread(state.threads, threadId, (thread) => {
299	    const previousVisitedAtMs = thread.lastVisitedAt ? Date.parse(thread.lastVisitedAt) : NaN;
300	    if (
301	      Number.isFinite(previousVisitedAtMs) &&
302	      Number.isFinite(visitedAtMs) &&
303	      previousVisitedAtMs >= visitedAtMs
304	    ) {
305	      return thread;
306	    }
307	    return { ...thread, lastVisitedAt: at };
308	  });
309	  return threads === state.threads ? state : { ...state, threads };
310	}
