import { useCallback, useSyncExternalStore } from "react";
import { DEFAULT_THEME_ID, getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:custom-theme";

// Silently sync the light/dark toggle used by useTheme so the .dark class
// never conflicts.  localStorage.setItem in the same tab does NOT fire a
// StorageEvent, so this does not create a feedback loop.
const LEGACY_THEME_KEY = "t3code:theme";

let listeners: Array<() => void> = [];
let cachedId: string | null = null;
let cachedTheme: Theme | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  return raw && raw.trim() ? raw : DEFAULT_THEME_ID;
}

function applyCustomTheme(theme: Theme, suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Override core palette CSS vars so all Tailwind color utilities update.
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--card", theme.colors.editor);
  root.style.setProperty("--card-foreground", theme.colors.foreground);
  root.style.setProperty("--popover", theme.colors.editor);
  root.style.setProperty("--popover-foreground", theme.colors.foreground);
  root.style.setProperty("--primary", theme.colors.accent);

  // Theme-specific semantic vars (consumed by future sidebar/editor/terminal
  // components via var(--theme-*) references).
  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--theme-editor", theme.colors.editor);
  root.style.setProperty("--theme-terminal", theme.colors.terminal);
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);

  // Font overrides — picked up by body via var(--font-family) / var(--font-size-base).
  root.style.setProperty("--font-family", theme.fontFamily);
  root.style.setProperty("--font-size-base", `${theme.fontSize}px`);

  // Sync the .dark class so CSS @variant dark and useTheme agree.
  const isDark = theme.colorScheme === "dark";
  root.classList.toggle("dark", isDark);

  // Silently sync the legacy theme key.
  localStorage.setItem(LEGACY_THEME_KEY, isDark ? "dark" : "light");

  if (suppressTransitions) {
    // Force a reflow so no-transitions takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash.
applyCustomTheme(getTheme(getStoredId()));

function getSnapshot(): Theme {
  const id = getStoredId();
  if (cachedId === id && cachedTheme !== null) {
    return cachedTheme;
  }
  cachedId = id;
  cachedTheme = getTheme(id);
  return cachedTheme;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      const theme = getTheme(getStoredId());
      applyCustomTheme(theme, true);
      cachedId = null;
      cachedTheme = null;
      emitChange();
    }
  };

  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useCustomTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((next: Theme) => {
    localStorage.setItem(STORAGE_KEY, next.id);
    cachedId = next.id;
    cachedTheme = next;
    applyCustomTheme(next, true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  return { theme, setTheme, availableThemes } as const;
}

