import { useCustomTheme } from "../hooks/useCustomTheme";

export function ThemeSelector() {
  const { theme: currentTheme, setTheme, availableThemes } = useCustomTheme();

  return (
    <div className="grid grid-cols-1 gap-2 sm:grid-cols-3" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
        const selected = currentTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex flex-col rounded-lg border px-3 py-3 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t)}
          >
            {/* Color swatches: background, foreground, accent, sidebar */}
            <div className="mb-2 flex gap-1.5">
              <span
                className="size-4 rounded-full border border-black/10"
                style={{ background: t.colors.background }}
                title="Background"
                aria-hidden="true"
              />
              <span
                className="size-4 rounded-full border border-black/10"
                style={{ background: t.colors.foreground }}
                title="Foreground"
                aria-hidden="true"
              />
              <span
                className="size-4 rounded-full border border-black/10"
                style={{ background: t.colors.accent }}
                title="Accent"
                aria-hidden="true"
              />
              <span
                className="size-4 rounded-full border border-black/10"
                style={{ background: t.colors.sidebar }}
                title="Sidebar"
                aria-hidden="true"
              />
            </div>

            <span className="flex items-center justify-between gap-1">
              <span className="text-sm font-medium">{t.name}</span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </span>
          </button>
        );
      })}
    </div>
  );
}

