export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface Theme {
  id: string;
  name: string;
  colors: ThemeColors;
  fontFamily: string;
  fontSize: number;
  colorScheme: "light" | "dark";
}

const BUILT_IN_THEMES: Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colorScheme: "dark",
    colors: {
      background: "#0d0d0f",
      foreground: "#f0f0f0",
      accent: "#7c60d5",
      sidebar: "#111113",
      editor: "#131316",
      terminal: "#0a0a0c",
      statusBar: "#1a1a1e",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colorScheme: "light",
    colors: {
      background: "#ffffff",
      foreground: "#1a1a1a",
      accent: "#5b4ecf",
      sidebar: "#f5f5f7",
      editor: "#fafafa",
      terminal: "#f8f8f8",
      statusBar: "#ededf0",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colorScheme: "dark",
    colors: {
      background: "#050510",
      foreground: "#c8d0e8",
      accent: "#6a8ff5",
      sidebar: "#080818",
      editor: "#060614",
      terminal: "#040410",
      statusBar: "#0b0b22",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
];

const THEME_MAP = new Map<string, Theme>(BUILT_IN_THEMES.map((t) => [t.id, t]));

export const DEFAULT_THEME_ID = "t3-dark";

export function getTheme(id: string): Theme {
  return THEME_MAP.get(id) ?? (THEME_MAP.get(DEFAULT_THEME_ID) as Theme);
}

export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

